using Microsoft.AspNetCore.Authorization;
using Microsoft.AspNetCore.Mvc;
using BuckeyeMarketplaceAPI.Models;

namespace BuckeyeMarketplaceAPI.Controllers
{
    [ApiController]
    [Route("api/[controller]")]
    public class ProductsController : ControllerBase
    {
        private static List<Product> products = new List<Product>
        {
            new Product { Id = 1, Title = "Introduction to Information Systems textbook", Description = "Comprehensive textbook for IS fundamentals", Category = "Textbooks", Price = 89.99m, SellerName = "John Smith", PostedDate = new DateTime(2026, 2, 15), ImageUrl = "https://m.media-amazon.com/images/I/61wDhC8nNGL._AC_UF1000,1000_QL80_.jpg" },
            new Product { Id = 2, Title = "Ohio State Sweatshirt - Medium", Description = "Official Ohio State University sweatshirt", Category = "Apparel", Price = 34.99m, SellerName = "Emma Johnson", PostedDate = new DateTime(2026, 2, 20), ImageUrl = "data:image/jpeg;base64," },
            new Product { Id = 3, Title = "Organic Chemistry Textbook", Description = "Advanced organic chemistry reference", Category = "Textbooks", Price = 129.99m, SellerName = "Alex Martinez", PostedDate = new DateTime(2026, 2, 18), ImageUrl = "data:image/jpeg;base64," },
            new Product { Id = 4, Title = "Desk Lamp", Description = "LED desk lamp with adjustable brightness", Category = "Electronics", Price = 24.99m, SellerName = "Sarah Lee", PostedDate = new DateTime(2026, 2, 25), ImageUrl = "https://encrypted-tbn2.gstatic.com/shopping?q=tbn:ANd9GcRQDvUa6IAUeyY01b9MIIP3a8rZcNZQq-kVNR0ylUQpERW9KsT7UtDHQD5Hab91d8Q-JZGCopcfrnPiXptjLaRR2qXx1KHXM5RnAbyR-nYfEB7r_4Hyhxt0rA" },
            new Product { Id = 5, Title = "Winter Coat", Description = "Warm winter coat with waterproof exterior", Category = "Apparel", Price = 99.99m, SellerName = "Michael Brown", PostedDate = new DateTime(2026, 2, 22), ImageUrl = "data:image/jpeg;base64," },
            new Product { Id = 6, Title = "TV", Description = "55-inch 4K Smart TV", Category = "Electronics", Price = 399.99m, SellerName = "David Wilson", PostedDate = new DateTime(2026, 2, 28), ImageUrl = "data:image/jpeg;base64," },
            new Product { Id = 7, Title = "Mini Refrigerator", Description = "Compact mini fridge for dorm or office", Category = "Appliances", Price = 79.99m, SellerName = "Jessica Garcia", PostedDate = new DateTime(2026, 3, 1), ImageUrl = "data:image/jpeg;base64," },
            new Product { Id = 8, Title = "Ohio State Jacket", Description = "Official Ohio State University jacket", Category = "Apparel", Price = 64.99m, SellerName = "Christopher Davis", PostedDate = new DateTime(2026, 2, 26), ImageUrl = "data:image/jpeg;base64," },
            new Product { Id = 9, Title = "Mirror", Description = "Large wall mirror with wooden frame", Category = "Home Decor", Price = 44.99m, SellerName = "Amanda Rodriguez", PostedDate = new DateTime(2026, 3, 2), ImageUrl = "data:image/jpeg;base64," }
        };

        /// <summary>
        /// Static helper so other controllers (e.g. CartController) can look up a product by ID
        /// from the shared in-memory list.
        /// </summary>
        public static Product? GetProductById(int id)
        {
            return products.FirstOrDefault(p => p.Id == id);
        }

        [HttpGet]
        public ActionResult<IEnumerable<Product>> GetProducts()
        {
            return Ok(products);
        }

        [HttpGet("{id}")]
        public ActionResult<Product> GetProduct(int id)
        {
            var product = products.FirstOrDefault(p => p.Id == id);
            if (product == null)
                return NotFound();
            return Ok(product);
        }

        [Authorize(Roles = "Admin")]
        [HttpPost]
        public ActionResult<Product> CreateProduct(Product product)
        {
            products.Add(product);
            return CreatedAtAction(nameof(GetProduct), new { id = product.Id }, product);
        }

        [Authorize(Roles = "Admin")]
        [HttpPut("{id}")]
        public IActionResult UpdateProduct(int id, Product product)
        {
            var existingProduct = products.FirstOrDefault(p => p.Id == id);
            if (existingProduct == null)
                return NotFound();

            existingProduct.Title = product.Title;
            existingProduct.Description = product.Description;
            existingProduct.Category = product.Category;
            existingProduct.Price = product.Price;
            existingProduct.SellerName = product.SellerName;
            existingProduct.ImageUrl = product.ImageUrl;
            existingProduct.StockQuantity = product.StockQuantity;
            existingProduct.PostedDate = product.PostedDate;

            return NoContent();
        }

        [Authorize(Roles = "Admin")]
        [HttpDelete("{id}")]
        public IActionResult DeleteProduct(int id)
        {
            var product = products.FirstOrDefault(p => p.Id == id);
            if (product == null)
                return NotFound();

            products.Remove(product);
            return NoContent();
        }
    }
}
